dashboard.definition:
{
  "title": "Endpoint & Cloud — Event Builder For Splunk",
  "description": "EDR detections, cloud IAM changes, Kubernetes audit events, and database query activity.",
  "layout": {
    "type": "grid",
    "options": {
      "width": 1440,
      "height": 1300,
      "backgroundColor": "#171D21"
    },
    "structure": [
      { "item": "viz_edr_critical_kpi",   "type": "block", "position": { "x": 0,    "y": 0,   "w": 360, "h": 200 } },
      { "item": "viz_aws_events_kpi",     "type": "block", "position": { "x": 360,  "y": 0,   "w": 360, "h": 200 } },
      { "item": "viz_k8s_events_kpi",     "type": "block", "position": { "x": 720,  "y": 0,   "w": 360, "h": 200 } },
      { "item": "viz_db_queries_kpi",     "type": "block", "position": { "x": 1080, "y": 0,   "w": 360, "h": 200 } },
      { "item": "viz_edr_by_severity",    "type": "block", "position": { "x": 0,    "y": 200, "w": 480, "h": 350 } },
      { "item": "viz_cs_tactics",         "type": "block", "position": { "x": 480,  "y": 200, "w": 480, "h": 350 } },
      { "item": "viz_edr_timeline",       "type": "block", "position": { "x": 960,  "y": 200, "w": 480, "h": 350 } },
      { "item": "viz_aws_iam_changes",    "type": "block", "position": { "x": 0,    "y": 550, "w": 480, "h": 300 } },
      { "item": "viz_gcp_ops",            "type": "block", "position": { "x": 480,  "y": 550, "w": 480, "h": 300 } },
      { "item": "viz_k8s_privileged",     "type": "block", "position": { "x": 960,  "y": 550, "w": 480, "h": 300 } },
      { "item": "viz_db_top_queries",     "type": "block", "position": { "x": 0,    "y": 850, "w": 720, "h": 300 } },
      { "item": "viz_saas_events",        "type": "block", "position": { "x": 720,  "y": 850, "w": 720, "h": 300 } },
      { "item": "viz_edr_detail",         "type": "block", "position": { "x": 0,    "y": 1150,"w": 1440,"h": 150 } }
    ],
    "globalInputs": ["input_time_range"]
  },
  "inputs": {
    "input_time_range": {
      "type": "input.timerange",
      "options": { "token": "time_range", "defaultValue": "-60m,now" },
      "title": "Time Range"
    }
  },
  "dataSources": {
    "ds_edr_critical_kpi": {
      "type": "ds.search",
      "options": {
        "query": "index=edr (sourcetype=crowdstrike:falcon:json OR sourcetype=ms:defender:atp OR sourcetype=sentinelone:activity) | eval sev=lower(coalesce(severity, Severity, \"unknown\")) | where sev=\"critical\" OR sev=\"high\" | stats count as critical_detections",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_aws_events_kpi": {
      "type": "ds.search",
      "options": {
        "query": "index=aws sourcetype=aws:cloudtrail | stats count as aws_events",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_k8s_events_kpi": {
      "type": "ds.search",
      "options": {
        "query": "index=kubernetes (sourcetype=kube:apiserver:audit OR sourcetype=docker:events) | stats count as k8s_events",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_db_queries_kpi": {
      "type": "ds.search",
      "options": {
        "query": "index=database (sourcetype=mysql:generalquery OR sourcetype=postgresql) | stats count as db_queries",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_edr_by_severity": {
      "type": "ds.search",
      "options": {
        "query": "index=edr (sourcetype=crowdstrike:falcon:json OR sourcetype=ms:defender:atp OR sourcetype=sentinelone:activity) | eval sev=coalesce(severity, Severity, \"Unknown\") | stats count BY sev | sort -count",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_cs_tactics": {
      "type": "ds.search",
      "options": {
        "query": "index=edr sourcetype=crowdstrike:falcon:json | eval tactic=coalesce(Tactic, TacticId, \"Unknown\") | where tactic!=\"Unknown\" | stats count BY tactic | sort -count | head 10",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_edr_timeline": {
      "type": "ds.search",
      "options": {
        "query": "index=edr (sourcetype=crowdstrike:falcon:json OR sourcetype=ms:defender:atp OR sourcetype=sentinelone:activity) | eval sev=coalesce(severity, Severity, \"Unknown\") | timechart span=5m count BY sev",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_aws_iam_changes": {
      "type": "ds.search",
      "options": {
        "query": "index=aws sourcetype=aws:cloudtrail | eval eventName=coalesce(eventName, \"Unknown\") | where match(eventName, \"(?i)(CreateUser|DeleteUser|AttachPolicy|DetachPolicy|CreateAccessKey|AddUserToGroup|CreateRole|PutUserPolicy)\") | stats count BY eventName | sort -count | head 10",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_gcp_ops": {
      "type": "ds.search",
      "options": {
        "query": "index=gcp sourcetype=google:gcp:audit | eval method=coalesce(methodName, protoPayload.methodName, \"Unknown\") | stats count BY method | sort -count | head 10",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_k8s_privileged": {
      "type": "ds.search",
      "options": {
        "query": "index=kubernetes sourcetype=kube:apiserver:audit | eval verb=coalesce(verb, requestVerb) | eval resource=coalesce(objectRef.resource, resource) | eval namespace=coalesce(objectRef.namespace, \"default\") | where verb=\"create\" AND resource=\"pods\" | eval privileged=if(match(_raw, \"privileged.*true|runAsUser.*0|hostPID.*true\"), \"Privileged\", \"Standard\") | stats count BY namespace, privileged | sort -count",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_db_top_queries": {
      "type": "ds.search",
      "options": {
        "query": "index=database (sourcetype=mysql:generalquery OR sourcetype=postgresql) | eval db_user=coalesce(user, db_user, \"Unknown\") | eval query_type=case(match(_raw, \"(?i)SELECT\"), \"SELECT\", match(_raw, \"(?i)INSERT\"), \"INSERT\", match(_raw, \"(?i)UPDATE\"), \"UPDATE\", match(_raw, \"(?i)DELETE\"), \"DELETE\", match(_raw, \"(?i)DROP\"), \"DROP\", match(_raw, \"(?i)CREATE\"), \"CREATE\", true(), \"OTHER\") | stats count BY db_user, query_type | sort -count | head 20",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_saas_events": {
      "type": "ds.search",
      "options": {
        "query": "index=saas sourcetype=salesforce:eventlogfile | eval event_type=coalesce(EventType, event_type, \"Unknown\") | eval user=coalesce(USER_ID_DERIVED, UserId, \"Unknown\") | stats count BY event_type | sort -count | head 10",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    },
    "ds_edr_detail": {
      "type": "ds.search",
      "options": {
        "query": "index=edr (sourcetype=crowdstrike:falcon:json OR sourcetype=ms:defender:atp OR sourcetype=sentinelone:activity) | eval device=coalesce(ComputerName, DeviceName, host) | eval sev=coalesce(severity, Severity, \"Unknown\") | eval tactic=coalesce(Tactic, technique, \"Unknown\") | table _time, sourcetype, device, sev, tactic, _raw | sort -_time | head 30",
        "queryParameters": { "earliest": "$time_range.earliest$", "latest": "$time_range.latest$" }
      }
    }
  },
  "visualizations": {
    "viz_edr_critical_kpi": {
      "type": "viz.singlevalue",
      "dataSources": { "primary": "ds_edr_critical_kpi" },
      "options": { "majorField": "critical_detections", "majorColor": "#FF2B2B", "backgroundColor": "transparent", "majorFontSize": 48 },
      "title": "Critical/High EDR Alerts"
    },
    "viz_aws_events_kpi": {
      "type": "viz.singlevalue",
      "dataSources": { "primary": "ds_aws_events_kpi" },
      "options": { "majorField": "aws_events", "majorColor": "#FF9900", "backgroundColor": "transparent", "majorFontSize": 48 },
      "title": "AWS CloudTrail Events"
    },
    "viz_k8s_events_kpi": {
      "type": "viz.singlevalue",
      "dataSources": { "primary": "ds_k8s_events_kpi" },
      "options": { "majorField": "k8s_events", "majorColor": "#326CE5", "backgroundColor": "transparent", "majorFontSize": 48 },
      "title": "Kubernetes Events"
    },
    "viz_db_queries_kpi": {
      "type": "viz.singlevalue",
      "dataSources": { "primary": "ds_db_queries_kpi" },
      "options": { "majorField": "db_queries", "majorColor": "#6495ED", "backgroundColor": "transparent", "majorFontSize": 48 },
      "title": "Database Queries"
    },
    "viz_edr_by_severity": {
      "type": "viz.pie",
      "dataSources": { "primary": "ds_edr_by_severity" },
      "options": { "labelField": "sev", "valueField": "count", "backgroundColor": "transparent" },
      "title": "EDR Detections by Severity"
    },
    "viz_cs_tactics": {
      "type": "viz.bar",
      "dataSources": { "primary": "ds_cs_tactics" },
      "options": { "xAxisTitleText": "MITRE Tactic", "yAxisTitleText": "Count", "legendDisplay": "off", "backgroundColor": "transparent" },
      "title": "CrowdStrike MITRE ATT&CK Tactics"
    },
    "viz_edr_timeline": {
      "type": "viz.line",
      "dataSources": { "primary": "ds_edr_timeline" },
      "options": { "xAxisTitleText": "Time", "yAxisTitleText": "Detections", "legendDisplay": "bottom", "backgroundColor": "transparent" },
      "title": "EDR Detections Over Time"
    },
    "viz_aws_iam_changes": {
      "type": "viz.bar",
      "dataSources": { "primary": "ds_aws_iam_changes" },
      "options": { "xAxisTitleText": "Event", "yAxisTitleText": "Count", "legendDisplay": "off", "backgroundColor": "transparent" },
      "title": "AWS IAM Change Events"
    },
    "viz_gcp_ops": {
      "type": "viz.bar",
      "dataSources": { "primary": "ds_gcp_ops" },
      "options": { "xAxisTitleText": "Method", "yAxisTitleText": "Count", "legendDisplay": "off", "backgroundColor": "transparent" },
      "title": "GCP Audit Operations"
    },
    "viz_k8s_privileged": {
      "type": "viz.table",
      "dataSources": { "primary": "ds_k8s_privileged" },
      "options": { "backgroundColor": "transparent", "count": 15 },
      "title": "K8s Pod Creation by Namespace & Type"
    },
    "viz_db_top_queries": {
      "type": "viz.table",
      "dataSources": { "primary": "ds_db_top_queries" },
      "options": { "backgroundColor": "transparent", "count": 15 },
      "title": "Database Queries by User & Type"
    },
    "viz_saas_events": {
      "type": "viz.bar",
      "dataSources": { "primary": "ds_saas_events" },
      "options": { "xAxisTitleText": "Event Type", "yAxisTitleText": "Count", "legendDisplay": "off", "backgroundColor": "transparent" },
      "title": "Salesforce Event Types"
    },
    "viz_edr_detail": {
      "type": "viz.table",
      "dataSources": { "primary": "ds_edr_detail" },
      "options": { "backgroundColor": "transparent", "count": 10 },
      "title": "Recent EDR Events"
    }
  }
}
